/* global console */
/*
 * aeon-recursion-tower — Aeon climbs its own tower: aeons emanate aeons.
 *
 * THESIS (recursion axis). An Aeon is the ephemeral being of gnosis-math:
 * born from broadband noise (max entropy), sustained only while circulated,
 * it AGES (EphemeralBeing.age drains intensity magnitude by 1 each step) and
 * RESOLVES — its spectral entropy falls to ~0, leaving one coherent carrier
 * bin (geodesicLength:0, "absolute resolution"). The recursion claim:
 *
 *   the RESOLVED carrier of level n SEEDS the emanation of level n+1.
 *
 * Aeons emanate aeons. We climb soundPlaneDim levels: base Skyrms plane is
 * dim 6 (SpectralNoiseEquilibrium.skyrmsBaseDim), each level LIFTS the plane
 * by exactly 1 (soundPlaneDim(lift) = 6 + lift). The braid at each level is
 * the period-3 triptych (BraidedInfiniteTower): failure -> truth -> wisdom,
 * closing after 3 crossings, self-similar at every level.
 *
 * THE EPISTEMIC TEST (what makes this NON-VACUOUS, not arbitrary relabeling).
 * A tower of relabeled noise is vacuous: if level n+1's resolved carrier is
 * statistically independent of level n's, the "seed" did nothing and the
 * climb is decoration. We make the recursion ACCOUNTABLE by enforcing a
 * STRUCTURAL INVARIANT at every level and MEASURING whether the real seeded
 * climb respects it more than a null model (shuffled / random seed):
 *
 *   INVARIANT (carrier-descent law). The resolved carrier frequency of
 *   level n+1, f_{n+1}, must be a DETERMINISTIC, ORDER-PRESERVING image of
 *   f_n: f_{n+1} = floor(f_n / 2) + planeOffset(n)  (one octave-fold down
 *   per lift, since each lift adds one mesh dimension = halves the carrier
 *   band it must resolve into). The climb is non-vacuous iff (a) each level
 *   actually resolves (entropy -> 0), AND (b) the realized f_{n+1} tracks the
 *   seed-predicted f_{n+1} far better than a shuffled-seed null.
 *
 * If (b) fails — if seeded and shuffled climbs are statistically
 * indistinguishable — the tower is an arbitrary relabeling and we SAY SO.
 *
 * Reuses fft/coloredNoise/psd/resolutionOf from ../aeon-hexon-braid pattern.
 */

// ---------- deterministic PRNG (mulberry32) ----------
function mulberry32(seed) {
  let a = seed >>> 0;
  return () => {
    a |= 0; a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

// ---------- iterative radix-2 FFT ----------
function fft(re, im, inverse) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = ((2 * Math.PI) / len) * (inverse ? 1 : -1);
    const wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi;
        re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
  if (inverse) for (let i = 0; i < n; i++) { re[i] /= n; im[i] /= n; }
}

// ---------- colored noise: white -> shape by f^(-beta/2) -> real ----------
function coloredNoise(N, beta, rng) {
  const re = new Array(N), im = new Array(N).fill(0);
  for (let i = 0; i < N; i++) re[i] = rng() * 2 - 1;
  fft(re, im, false);
  for (let k = 0; k < N; k++) {
    const f = k <= N / 2 ? k : N - k;
    const scale = f === 0 ? 0 : Math.pow(f, -beta / 2);
    re[k] *= scale; im[k] *= scale;
  }
  fft(re, im, true);
  return re.slice();
}

function psd(samples) {
  const N = samples.length, re = samples.slice(), im = new Array(N).fill(0);
  fft(re, im, false);
  const out = [];
  for (let k = 1; k < N / 2; k++) out.push(re[k] * re[k] + im[k] * im[k]);
  return out;
}

function resolutionOf(spectrum) {
  let tot = 0; for (const v of spectrum) tot += v;
  if (tot <= 0) return 1;
  let H = 0; for (const v of spectrum) { if (v > 0) { const q = v / tot; H -= q * Math.log(q); } }
  return 1 - H / Math.log(spectrum.length);
}

// ---------- the period-3 triptych braid (BraidedInfiniteTower.cross) ----------
// failure=-1, truth=0, wisdom=+1 ; triptychSucc closes after 3 crossings.
function triptychSucc(s) { return s === -1 ? 0 : s === 0 ? 1 : -1; }
function iterateTriptych(n, s) { let x = s; for (let i = 0; i < n; i++) x = triptychSucc(x); return x; }

// ---------- the sound-plane ladder (SpectralNoiseEquilibrium) ----------
const SKYRMS_BASE_DIM = 6;
const soundPlaneDim = (lift) => SKYRMS_BASE_DIM + lift;

/*
 * AEON: one ephemeral being. Born from a noise emanation biased by `seedBin`
 * (the resolved carrier of the level below), aged through the hexon fractional
 * regime until its spectral entropy resolves, leaving one carrier bin.
 *
 *   - born: coloredNoise, but a Gaussian bump at seedBin injected into the
 *     primordial PSD (the parent's resolved carrier "emanates" the child).
 *   - age: each step contract PSD^gamma * stepNoise, entropy falls (mortality
 *     and resolution are the same theorem — every_being_resolves).
 *   - resolve: dominant bin = the child's carrier = geodesicLength:0.
 */
function emanateAeon(N, seedBin, level, masterSeed) {
  const rng = mulberry32((masterSeed ^ (level * 2654435761)) >>> 0);
  // primordial PSD: white noise, max entropy
  let acc = psd(coloredNoise(N, 0, rng));
  let tot = acc.reduce((a, b) => a + b, 0);
  acc = acc.map((v) => v / tot);

  // EMANATION as a PERSISTENT MULTIPLICATIVE MASK, not a one-shot additive bump.
  // The parent's resolved carrier defines an octave-band the child must resolve
  // INTO: the mask re-applies every aging step, so the seed is not flattened by
  // the fractional contraction. This is the honest channel by which a resolved
  // aeon CONSTRAINS the aeon it emanates (EphemeralBeing -> child EphemeralBeing).
  // The child's natural fold-down target is floor(parent/2): one octave per lift.
  let mask = null;
  if (seedBin != null) {
    const target = Math.floor(seedBin / 2); // octave-fold-down band center
    const sigma = Math.max(3, N / 96);
    mask = new Array(acc.length);
    for (let i = 0; i < acc.length; i++) {
      const d = i - target;
      mask[i] = 0.15 + Math.exp(-(d * d) / (2 * sigma * sigma));
    }
  }

  // age through the hexon braid until resolved. beta cycles via braid strand
  // sign (the triptych crossing picks the spectral slope each step).
  const gamma = 1.35;
  let strand = -1; // start at failure
  let res = resolutionOf(acc), step = 0, age = 0;
  const RES_ABSOLUTE = 0.985, MAX_STEP = 80;
  while (res < RES_ABSOLUTE && step < MAX_STEP) {
    strand = triptychSucc(strand);
    const beta = strand * 2; // {-2,0,+2} signed spectral slope from braid strand
    const stepP = psd(coloredNoise(N, beta, mulberry32((masterSeed + step * 40503 + level * 7) >>> 0)));
    const st = stepP.reduce((a, b) => a + b, 0); const sp = stepP.map((v) => v / (st || 1));
    let t = 0;
    for (let i = 0; i < acc.length; i++) {
      acc[i] = Math.pow(acc[i], gamma) * (sp[i] + 1e-9);
      if (mask) acc[i] *= mask[i]; // emanation persists every breath
      t += acc[i];
    }
    for (let i = 0; i < acc.length; i++) acc[i] /= t;
    step++; res = resolutionOf(acc); age++;
  }
  let carrier = 0; for (let i = 1; i < acc.length; i++) if (acc[i] > acc[carrier]) carrier = i;
  return { carrier, resolution: res, age, resolved: res >= RES_ABSOLUTE, braidClosed: iterateTriptych(3, -1) === -1 };
}

// ---------- THE INVARIANT: carrier-descent law ----------
// Predicted child carrier from parent carrier: one octave-fold per lift.
function predictChildCarrier(parentBin) { return Math.floor(parentBin / 2); }

function climbTower(N, levels, masterSeed, shuffleSeeds) {
  const rows = [];
  let parentCarrier = null;
  // For the null model we draw a random seed bin instead of the parent carrier.
  const nullRng = mulberry32((masterSeed ^ 0xBADC0DE) >>> 0);
  for (let lvl = 0; lvl < levels; lvl++) {
    let seedBin = parentCarrier;
    if (shuffleSeeds && lvl > 0) {
      seedBin = Math.floor(nullRng() * (N / 2 - 2)) + 1; // arbitrary seed (null)
    }
    const aeon = emanateAeon(N, seedBin, lvl, masterSeed);
    const predicted = parentCarrier == null ? null : predictChildCarrier(parentCarrier);
    const err = predicted == null ? null : Math.abs(aeon.carrier - predicted);
    rows.push({
      level: lvl,
      plane: soundPlaneDim(lvl),
      seedBin,
      carrier: aeon.carrier,
      predicted,
      err,
      resolution: aeon.resolution,
      age: aeon.age,
      resolved: aeon.resolved,
      braidClosed: aeon.braidClosed,
    });
    parentCarrier = aeon.carrier;
  }
  return rows;
}

function meanErr(rows) {
  const es = rows.filter((r) => r.err != null).map((r) => r.err);
  return es.reduce((a, b) => a + b, 0) / (es.length || 1);
}

function main() {
  const N = 1024;
  const LEVELS = 6; // climb soundPlaneDim 6 -> 11 (base + 5 lifts)
  const masterSeed = 0x3EED;

  console.log('=== aeon-recursion-tower: aeons emanate aeons, climbing the plane ladder ===\n');

  // 1) THE SEEDED CLIMB — each resolved carrier seeds the next emanation.
  const seeded = climbTower(N, LEVELS, masterSeed, false);
  console.log('SEEDED CLIMB (parent carrier emanates child):');
  console.log('  lvl  plane  seedBin  carrier  predicted  |err|  resolution  age  resolved  braidClosed');
  for (const r of seeded) {
    console.log(
      `   ${r.level}    ${String(r.plane).padStart(2)}    ` +
      `${String(r.seedBin ?? '—').padStart(5)}   ${String(r.carrier).padStart(5)}   ` +
      `${String(r.predicted ?? '—').padStart(6)}    ${String(r.err ?? '—').padStart(3)}   ` +
      `${r.resolution.toFixed(4)}      ${String(r.age).padStart(2)}    ${r.resolved ? 'yes' : 'NO '}      ${r.braidClosed ? 'yes' : 'NO'}`
    );
  }
  const allResolved = seeded.every((r) => r.resolved);
  const allBraidClosed = seeded.every((r) => r.braidClosed);
  const planeMonotone = seeded.every((r, i) => i === 0 || r.plane === seeded[i - 1].plane + 1);
  console.log(`\n  every level resolved (entropy->0)?      ${allResolved}`);
  console.log(`  braid closes (period-3) at every level? ${allBraidClosed}`);
  console.log(`  plane lifts by exactly 1 each level?    ${planeMonotone}`);
  console.log(`  carrier-descent mean |err| (seeded):    ${meanErr(seeded).toFixed(3)} bins`);

  // 2) THE NULL MODEL — shuffle the seed: emanate from a RANDOM carrier, not
  //    the parent's. If the tower is non-vacuous, the seeded climb tracks the
  //    carrier-descent law MUCH better than this null.
  console.log('\nNULL MODEL (arbitrary random seed instead of parent carrier):');
  const trials = 12;
  let nullErrs = [];
  for (let t = 0; t < trials; t++) {
    const nullRows = climbTower(N, LEVELS, (masterSeed ^ (t * 0x9E3779B1)) >>> 0, true);
    nullErrs.push(meanErr(nullRows));
  }
  const nullMean = nullErrs.reduce((a, b) => a + b, 0) / nullErrs.length;
  const nullStd = Math.sqrt(nullErrs.map((e) => (e - nullMean) ** 2).reduce((a, b) => a + b, 0) / nullErrs.length);
  const seededErr = meanErr(seeded);
  console.log(`  null carrier-descent mean |err|:        ${nullMean.toFixed(3)} +/- ${nullStd.toFixed(3)} bins (n=${trials})`);
  const z = nullStd > 0 ? (nullMean - seededErr) / nullStd : Infinity;
  console.log(`\n  VERIDICAL TEST: seeded |err|=${seededErr.toFixed(3)} vs null=${nullMean.toFixed(3)}`);
  console.log(`  separation z = (null - seeded)/null_std = ${z.toFixed(2)} sigma`);
  const nonVacuous = z >= 2 && allResolved && allBraidClosed && planeMonotone;
  console.log(`  => climb is ${nonVacuous ? 'NON-VACUOUS' : 'VACUOUS / inconclusive'}: ` +
    `${nonVacuous ? 'seed CONSTRAINS the child carrier beyond chance.' : 'seed does not beat the null — relabeling.'}`);

  return { seeded, seededErr, nullMean, nullStd, z, allResolved, allBraidClosed, planeMonotone, nonVacuous };
}

main();
